  'aecc3064-3bb3-4b11-9524-6046c1c52e77',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core Project Structure — MVC Layers vs. Vertical Slices$escape$,
  $escape$Traditional ASP.NET Core projects mirror MVC's horizontal layers: `Controllers/`, `Services/`, `Repositories/`, `Models/`. This feels organized until a feature spans six folders and a simple change requires touching half the solution. Vertical slice architecture flips this: organize by feature, not layer. Each feature folder owns its controller (or minimal API endpoint group), command/query handlers (via MediatR), validators, and DTOs. Changes stay localized. A `Features/Articles/CreateArticle/` folder contains `CreateArticleCommand.cs`, `CreateArticleHandler.cs`, `CreateArticleValidator.cs`, and `CreateArticleResponse.cs` — everything needed, nothing else. In `Program.cs`, register handlers with `builder.Services.AddMediatR(cfg => cfg.RegisterServicesFromAssembly(Assembly.GetExecutingAssembly()))` and scan validators via FluentValidation's `AddValidatorsFromAssembly`. Shared infrastructure (DbContext, auth, logging) lives in `Infrastructure/` — not per-feature. The result: feature cohesion without sacrificing cross-cutting concerns. For greenfield ASP.NET Core 8 projects, vertical slices scale far better than horizontal layering as team size and feature count grow.$escape$,
  $escape$// Features/Articles/CreateArticle/CreateArticleHandler.cs
public record CreateArticleCommand(string Title, string Body) : IRequest<ArticleDto>;

public class CreateArticleHandler(AppDbContext db) : IRequestHandler<CreateArticleCommand, ArticleDto>
{
    public async Task<ArticleDto> Handle(CreateArticleCommand cmd, CancellationToken ct)
    {
        var article = new Article { Title = cmd.Title, Body = cmd.Body };
        db.Articles.Add(article);
        await db.SaveChangesAsync(ct);
        return new ArticleDto(article.Id, article.Title);
    }
}$escape$,
  $escape$csharp$escape$,
