INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2cac1e5e-a844-4f57-b9a2-e5319ea43926',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core DI — Built-in Container vs Manual Wiring and What It Costs You in Tests$escape$,
  $escape$ASP.NET Core's built-in `IServiceCollection` handles constructor injection, lifetime management (Transient/Scoped/Singleton), and scope validation at startup. For most apps, it's enough — and avoiding a third-party container like Autofac removes one moving part from your stack.

The real testability payoff comes from how you register: prefer `AddScoped<IOrderService, OrderService>()` over `AddScoped<OrderService>()`. Binding to the abstraction means xUnit tests swap in a `Mock<IOrderService>` with zero friction — no `HttpContext`, no `WebApplicationFactory` needed for unit tests.

Lifetime mismatches are a silent killer. Injecting a Scoped service into a Singleton causes `ValidateScopes` to throw at startup (enabled by default in Development). Production silently captures stale scope state. Always call `builder.Services.BuildServiceProvider(new ServiceProviderOptions { ValidateScopes = true, ValidateOnBuild = true })` in CI to catch these early.

For integration tests, `WebApplicationFactory<Program>` lets you call `.WithWebHostBuilder(b => b.ConfigureServices(s => s.AddSingleton<IEmailSender, FakeEmailSender>()))` to override any registration — no reflection hacks required.$escape$,
  $escape$// Program.cs — prefer abstractions, enable validation
builder.Services.AddScoped<IOrderService, OrderService>();
builder.Services.AddSingleton<IEmailSender, SmtpEmailSender>();

// Catch lifetime mismatches in CI
var provider = builder.Services.BuildServiceProvider(
    new ServiceProviderOptions { ValidateScopes = true, ValidateOnBuild = true });

// Integration test override — WebApplicationFactory
var factory = new WebApplicationFactory<Program>()
    .WithWebHostBuilder(b =>
        b.ConfigureServices(s =>
            s.AddSingleton<IEmailSender, FakeEmailSender>()));$escape$,
  $escape$csharp$escape$,
