INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3a07bacc-0e50-4aea-a24a-ffd66b52f95f',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core Middleware — Pipeline Order, Global vs Route-Specific$escape$,
  $escape$ASP.NET Core's request pipeline is a chain of middleware components registered via `app.Use*()` in `Program.cs`. Order is deterministic and critical — each middleware calls `next()` to pass control downstream, then resumes on the way back. Authentication must precede Authorization; logging should wrap everything.

Global middleware (registered on `IApplicationBuilder`) runs on every request. For route-scoped behavior, use endpoint filters (`AddEndpointFilter`) or minimal API route groups with their own middleware chain via `MapGroup().Use*()`.

A common mistake: placing `app.UseAuthentication()` after `app.UseAuthorization()` silently breaks auth — claims are never populated when the authorization check runs. Similarly, `app.UseExceptionHandler()` must sit before all other middleware so it can catch downstream exceptions.

Use `app.UseWhen()` for conditional branching without short-circuiting the main pipeline, and `app.Map()` when you need a fully isolated sub-pipeline for a path prefix. Short-circuiting (not calling `next`) terminates the pipeline — intentional in auth failures, catastrophic if done accidentally in logging middleware.$escape$,
  $escape$var app = builder.Build();

app.UseExceptionHandler("/error");       // 1 — outermost
app.UseHttpsRedirection();               // 2
app.UseAuthentication();                 // 3 — populate ClaimsPrincipal
app.UseAuthorization();                  // 4 — evaluate claims

// Route-scoped middleware via MapGroup
var api = app.MapGroup("/api")
    .AddEndpointFilter<RateLimitFilter>(); // only hits /api/**

api.MapGet("/bytes", () => Results.Ok());

app.UseWhen(
    ctx => ctx.Request.Path.StartsWithSegments("/debug"),
    branch => branch.UseMiddleware<DiagnosticsMiddleware>()
);

app.Run();$escape$,
  $escape$csharp$escape$,
