INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7ccc4a7a-4744-4c8f-8491-7170fa7f44b4',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core Input Validation — Schema Validation at the Boundary, Sanitization, and Error Responses$escape$,
  $escape$ASP.NET Core validates request bodies automatically when you annotate your DTOs with Data Annotations and call `builder.Services.AddControllers()` — but that's table stakes. For Minimal APIs, validation doesn't fire automatically; you must invoke it explicitly or wire a filter. Use `IValidator<T>` from FluentValidation for complex rules: it gives you composable, testable validators without polluting your domain models. Register with `builder.Services.AddValidatorsFromAssemblyContaining<Program>()` and inject into endpoint handlers or add a `ValidationFilter<T>` via `app.MapPost(...).AddEndpointFilter<ValidationFilter<CreateByteRequest>>()`. Sanitization is separate from validation — strip HTML at the boundary using `HtmlEncoder.Default.Encode()` or `AngleSharp` for rich content. Never trust `ModelState.IsValid` alone for security-sensitive fields; layer explicit sanitization on top. For error responses, conform to RFC 9457 (Problem Details): ASP.NET Core 8 emits `ProblemDetails` by default when `ApiBehaviorOptions.SuppressModelStateInvalidFilter` is false, giving clients a structured `errors` map with field-level messages. Extend `ValidationProblemDetails` for custom FluentValidation failure projections.$escape$,
  $escape$// Minimal API + FluentValidation + ProblemDetails
app.MapPost("/bytes", async (CreateByteRequest req, IValidator<CreateByteRequest> validator, IByteService svc) =>
{
    var result = await validator.ValidateAsync(req);
    if (!result.IsValid)
        return Results.ValidationProblem(result.ToDictionary()); // RFC 9457

    var sanitizedTitle = HtmlEncoder.Default.Encode(req.Title);
    var created = await svc.CreateAsync(req with { Title = sanitizedTitle });
    return Results.Created($"/bytes/{created.Id}", created);
});

// FluentValidation rule
public class CreateByteRequestValidator : AbstractValidator<CreateByteRequest>
{
    public CreateByteRequestValidator()
    {
        RuleFor(x => x.Title).NotEmpty().MaximumLength(120);
        RuleFor(x => x.Body).NotEmpty().Length(50, 300);
    }
}$escape$,
