INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3be14244-6052-49f7-a091-6de22a167dab',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core Performance — Connection Pooling, Async Handlers, and Response Compression$escape$,
  $escape$Three settings that meaningfully change throughput in ASP.NET Core apps often go untouched after scaffolding. First, Npgsql's connection pool defaults (`MaxPoolSize=100`) are usually too conservative for high-concurrency APIs — bump it via the connection string and configure `NpgsqlDataSourceBuilder` for named pools per tenant. Second, every Minimal API or controller action that touches I/O must be `async Task<IResult>` — synchronous handlers block Kestrel's thread pool under load; there's no automatic offloading. Third, `app.UseResponseCompression()` is opt-in. Register `AddResponseCompression` with Brotli first, gzip as fallback, and set `EnableForHttps = true` only after confirming your deployment terminates TLS at the app level, not a reverse proxy. Stack all three with `app.UseResponseCaching()` and `OutputCache` middleware for endpoints with stable payloads. Benchmark with `bombardier` or `k6` before and after — the async fix alone typically cuts p99 latency by 30–60% on DB-heavy routes.$escape$,
  $escape$// Program.cs
builder.Services.AddResponseCompression(opts =>
{
    opts.EnableForHttps = false; // true only if Kestrel terminates TLS
    opts.Providers.Add<BrotliCompressionProvider>();
    opts.Providers.Add<GzipCompressionProvider>();
});

builder.Services.AddNpgsqlDataSource(
    builder.Configuration.GetConnectionString("Postgres")!,
    b => b.ConnectionStringBuilder.MaxPoolSize = 200);

var app = builder.Build();
app.UseResponseCompression();

app.MapGet("/bytes", async (NpgsqlDataSource ds) =>
{
    await using var conn = await ds.OpenConnectionAsync();
    // async I/O — never block here
    return Results.Ok();
});$escape$,
  $escape$csharp$escape$,
