INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6b096e46-dfa2-4954-a0e4-b4eb729b7bba',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core API Versioning — REST Conventions, Route Strategy, and OpenAPI in One Setup$escape$,
  $escape$ASP.NET Core's `Asp.Versioning.Http` package gives you URL-segment, query-string, and header versioning with minimal config. The idiomatic approach pairs `MapGroup` with `AddApiVersioning` and `AddApiExplorer` to generate per-version OpenAPI documents via Swashbuckle or the built-in `Microsoft.AspNetCore.OpenApi` (introduced in .NET 9). Register versioning once in `Program.cs`, then decorate each `RouteGroupBuilder` with `.HasApiVersion(1, 0)`. For REST conventions: use plural nouns (`/bytes`, not `/getBytes`), map HTTP verbs semantically (`POST` creates, `PUT` full-replace, `PATCH` partial), and return `201 Created` with a `Location` header on resource creation via `TypedResults.Created`. Deprecate old versions by tagging `.HasDeprecatedApiVersion(1, 0)` — the `api-deprecated-version` response header signals consumers automatically. OpenAPI metadata flows through `WithOpenApi()` on each endpoint, letting you annotate summaries and examples inline without XML doc comments. Combine this with `[Produces]`/`[Consumes]` attributes on groups to enforce consistent content negotiation across all routes in a version.$escape$,
  $escape$var builder = WebApplication.CreateBuilder(args);
builder.Services.AddApiVersioning(o => {
    o.DefaultApiVersion = new ApiVersion(1, 0);
    o.AssumeDefaultVersionWhenUnspecified = true;
    o.ReportApiVersions = true;
}).AddApiExplorer(o => {
    o.GroupNameFormat = "'v'VVV";
    o.SubstituteApiVersionInUrl = true;
});
builder.Services.AddOpenApi();
var app = builder.Build();
var v1 = app.NewVersionedApi("Bytes")
    .MapGroup("/api/v{version:apiVersion}/bytes")
    .HasApiVersion(1, 0)
    .WithOpenApi();
v1.MapGet("/", () => Results.Ok()).WithSummary("List bytes");
v1.MapPost("/", (CreateByteRequest req) =>
    TypedResults.Created($"/api/v1/bytes/1", req));
app.MapOpenApi();
app.Run();$escape$,
  $escape$csharp$escape$,
