INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7160cd7e-8ea0-4072-9e7a-dd4c4c2f3297',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core Monitoring — Health Checks, Metrics, and Distributed Tracing in One Pass$escape$,
  $escape$ASP.NET Core 8 ships three observability primitives out of the box. Health checks via `AddHealthChecks()` let you register named checks — database connectivity, external APIs, disk space — and expose them at `/health` with granular `HealthStatus` responses. Tag filters let k8s liveness and readiness probes hit separate subsets. For metrics, `AddOpenTelemetryMetrics()` wires into the built-in `System.Diagnostics.Metrics` API; the ASP.NET Core instrumentation library auto-emits request duration, active connections, and queue depth histograms — push them to Prometheus via `OpenTelemetry.Exporter.Prometheus.AspNetCore`. Distributed tracing uses `ActivitySource` and propagates W3C `traceparent` headers automatically through `HttpClient` and EF Core when you add `AddAspNetCoreInstrumentation()` and `AddEntityFrameworkCoreInstrumentation()`. All three pillars share one `IServiceCollection` registration pattern and export to the same OpenTelemetry collector, keeping your `Program.cs` composable. Pair with `dotnet-monitor` sidecar for on-demand dumps without redeployment.$escape$,
  $escape$var builder = WebApplication.CreateBuilder(args);

builder.Services.AddHealthChecks()
    .AddNpgsql(builder.Configuration["ConnectionStrings:Default"]!, tags: ["ready"]);

builder.Services.AddOpenTelemetry()
    .WithMetrics(m => m
        .AddAspNetCoreInstrumentation()
        .AddPrometheusExporter())
    .WithTracing(t => t
        .AddAspNetCoreInstrumentation()
        .AddEntityFrameworkCoreInstrumentation()
        .AddOtlpExporter());

var app = builder.Build();
app.MapHealthChecks("/health/live");
app.MapHealthChecks("/health/ready", new() { Predicate = c => c.Tags.Contains("ready") });
app.MapPrometheusScrapingEndpoint();
app.Run();$escape$,
  $escape$csharp$escape$,
