INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4d569186-4718-4989-9693-21d13d3bf16f',
  '00000000-0000-0000-0000-000000000001',
  $escape$ASP.NET Core Background Jobs — BackgroundService, Channels, and Worker Patterns$escape$,
  $escape$ASP.NET Core's `BackgroundService` (via `IHostedService`) is the backbone for long-running work. Inherit it, implement `ExecuteAsync(CancellationToken)`, and register with `builder.Services.AddHostedService<T>()`. For task queues, pair it with `System.Threading.Channels.Channel<T>` — a high-performance, built-in producer/consumer primitive. Your API enqueues work via `ChannelWriter<T>`, and your `BackgroundService` dequeues and processes via `ChannelReader<T>.ReadAllAsync()`. This avoids thread-unsafe `ConcurrentQueue` hacks and integrates naturally with `CancellationToken` propagation.

For scheduled jobs, ASP.NET Core has no built-in scheduler — use `PeriodicTimer` (introduced in .NET 6) inside `ExecuteAsync` instead of `Task.Delay` loops; it skips missed ticks cleanly. For production-grade scheduling with persistence and retries, Hangfire or Quartz.NET integrate cleanly via their ASP.NET Core packages.

For heavy workloads, extract the `BackgroundService` into a standalone Worker Service project (`dotnet new worker`) running as an Azure Container App job. It shares the same `IHostedService` model but decouples CPU-bound processing from your web API's request pipeline, preventing resource starvation.$escape$,
  $escape$// Channel-backed task queue with BackgroundService
var channel = Channel.CreateBounded<WorkItem>(new BoundedChannelOptions(100) {
    FullMode = BoundedChannelFullMode.Wait
});
builder.Services.AddSingleton(channel.Writer);
builder.Services.AddSingleton(channel.Reader);
builder.Services.AddHostedService<TaskQueueProcessor>();

public class TaskQueueProcessor(ChannelReader<WorkItem> reader) : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken ct)
    {
        await foreach (var item in reader.ReadAllAsync(ct))
            await ProcessAsync(item, ct);
    }
}$escape$,
